     1вҶ’import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
     2вҶ’import { InteractionManager, NativeSyntheticEvent, NativeScrollEvent } from 'react-native';
     3вҶ’import { useFocusEffect } from '@react-navigation/native';
     4вҶ’import { useShallow } from 'zustand/react/shallow';
     5вҶ’import type { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
     6вҶ’import type { propsItemsListCardTransition } from '@semparar/design-system-app/src/atomic/organisms/ListCardTransition/Models';
     7вҶ’import { getPointsExtract, getPointsBalance } from '../../services/services';
     8вҶ’import {
     9вҶ’  PointsExtractStatus,
    10вҶ’  PointsBalanceStatus,
    11вҶ’  type AppliedFilters,
    12вҶ’  type PointsTransaction,
    13вҶ’} from '../../services/models';
    14вҶ’import { eventScreenViewV3, eventSelectContent } from '~/constants/functions';
    15вҶ’import { EXTRACT_CONSTANTS } from '../../services/constants';
    16вҶ’import { ANALYTICS_EVENTS, SCREEN_STRINGS } from './data';
    17вҶ’import type {
    18вҶ’  ExtractRewardProgramProps,
    19вҶ’  UseExtractRewardProgramReturn,
    20вҶ’  FilterGroup,
    21вҶ’} from './Models';
    22вҶ’import { PERIOD_DAYS_MAP } from './Models';
    23вҶ’import { getFilteredTransactions, getFilteredTransactionsByText } from './utils';
    24вҶ’import { processPointsExtractData } from '../../services/repository';
    25вҶ’import useDebounce from '../../hooks/useDebounce';
    26вҶ’
    27вҶ’const SCROLL_THRESHOLD = 300;
    28вҶ’import { useRootStore } from '~/store';
    29вҶ’
    30вҶ’export function useExtractRewardProgramScreen(
    31вҶ’  params?: ExtractRewardProgramProps,
    32вҶ’): UseExtractRewardProgramReturn {
    33вҶ’  const hasTrackedScreenView = useRef(false);
    34вҶ’  const hasTrackedSearchPress = useRef(false);
    35вҶ’  const canLoadMoreRef = useRef(false);
    36вҶ’  const isLoadingMoreRef = useRef(false);
    37вҶ’
    38вҶ’  const modalizeRefInfo = useRef<PropsModalizeRef>(null as unknown as PropsModalizeRef);
    39вҶ’  const modalizeRefFilters = useRef<PropsModalizeRef>(null as unknown as PropsModalizeRef);
    40вҶ’
    41вҶ’  const [isRefreshing, setIsRefreshing] = useState(false);
    42вҶ’  const [transactionsData, setTransactionsData] = useState<propsItemsListCardTransition[]>([]);
    43вҶ’  const [searchText, setSearchText, debouncedSearchText] = useDebounce('', 400);
    44вҶ’
    45вҶ’  const { pointsExtract, pointsBalance, pointsExtractFilters, pointsExtractActions } =
    46вҶ’    useRootStore(
    47вҶ’      useShallow((state) => ({
    48вҶ’        pointsExtract: state.pointsExtract,
    49вҶ’        pointsBalance: state.pointsBalance,
    50вҶ’        pointsExtractFilters: state.pointsExtractFilters,
    51вҶ’        pointsExtractActions: state.pointsExtractActions,
    52вҶ’      })),
    53вҶ’    );
    54вҶ’
    55вҶ’  const isLoadingExtract = pointsExtract.status === PointsExtractStatus.LOADING;
    56вҶ’  const isLoadingMore = pointsExtract.isLoadingMore;
    57вҶ’  const isLoadingBalance = pointsBalance.status === PointsBalanceStatus.LOADING;
    58вҶ’  const appliedTransactionsFilters = pointsExtractFilters.appliedTransactionsFilters;
    59вҶ’  const hasError = 
    60вҶ’    pointsExtract.status === PointsExtractStatus.ERROR && 
    61вҶ’    !isLoadingExtract && 
    62вҶ’    (!pointsExtract.extractData || !pointsExtract.extractData.transactions?.length);
    63вҶ’
    64вҶ’  useFocusEffect(
    65вҶ’    useCallback(() => {
    66вҶ’      if (!hasTrackedScreenView.current) {
    67вҶ’        eventScreenViewV3(
    68вҶ’          ANALYTICS_EVENTS.SCREEN_VIEW.screen_name,
    69вҶ’          ANALYTICS_EVENTS.SCREEN_VIEW.screen_class,
    70вҶ’          ANALYTICS_EVENTS.SCREEN_VIEW.screen_bussines,
    71вҶ’          {
    72вҶ’            location_1: ANALYTICS_EVENTS.SCREEN_VIEW.location_1,
    73вҶ’            location_2: ANALYTICS_EVENTS.SCREEN_VIEW.location_2,
    74вҶ’            location_3: ANALYTICS_EVENTS.SCREEN_VIEW.location_3,
    75вҶ’          },
    76вҶ’        );
    77вҶ’        hasTrackedScreenView.current = true;
    78вҶ’      }
    79вҶ’
    80вҶ’      return () => {
    81вҶ’        hasTrackedScreenView.current = false;
    82вҶ’      };
    83вҶ’    }, []),
    84вҶ’  );
    85вҶ’
    86вҶ’  const refreshExtractData = useCallback(() => {
    87вҶ’    pointsExtractActions.setExtractStatus(PointsExtractStatus.IDLE);
    88вҶ’    pointsExtractActions.setBalanceStatus(PointsBalanceStatus.IDLE);
    89вҶ’    pointsExtractActions.setLoadingMore(false);
    90вҶ’    getPointsBalance();
    91вҶ’    getPointsExtract({ page: EXTRACT_CONSTANTS.DEFAULT_PAGE });
    92вҶ’  }, [pointsExtractActions]);
    93вҶ’
    94вҶ’  useFocusEffect(
    95вҶ’    useCallback(() => {
    96вҶ’      refreshExtractData();
    97вҶ’    }, [refreshExtractData]),
    98вҶ’  );
    99вҶ’
   100вҶ’  useEffect(() => {
   101вҶ’    const shouldFetchBalance =
   102вҶ’      pointsBalance.points === undefined ||
   103вҶ’      pointsBalance.status === PointsBalanceStatus.ERROR;
   104вҶ’
   105вҶ’    if (shouldFetchBalance) {
   106вҶ’      getPointsBalance();
   107вҶ’    }
   108вҶ’
   109вҶ’    getPointsExtract({ page: EXTRACT_CONSTANTS.DEFAULT_PAGE });
   110вҶ’  }, [pointsBalance.points, pointsBalance.status]);
   111вҶ’
   112вҶ’  useEffect(() => {
   113вҶ’    if (!isLoadingExtract && isRefreshing) {
   114вҶ’      setIsRefreshing(false);
   115вҶ’    }
   116вҶ’  }, [isLoadingExtract, isRefreshing]);
   117вҶ’
   118вҶ’  useEffect(() => {
   119вҶ’    if (searchText.length === 0) {
   120вҶ’      hasTrackedSearchPress.current = false;
   121вҶ’    }
   122вҶ’  }, [searchText]);
   123вҶ’
   124вҶ’  const getPointsAvailable = useMemo(() => {
   125вҶ’    return pointsBalance.points ?? 0;
   126вҶ’  }, [pointsBalance.points]);
   127вҶ’
   128вҶ’  const handleGoBack = useCallback(() => {
   129вҶ’    params?.navigation?.goBack();
   130вҶ’  }, [params?.navigation]);
   131вҶ’
   132вҶ’  const requestPointsExtract = useCallback(() => {
   133вҶ’    getPointsExtract({ page: EXTRACT_CONSTANTS.DEFAULT_PAGE });
   134вҶ’  }, []);
   135вҶ’
   136вҶ’  const handleLoadMore = useCallback(() => {
   137вҶ’    const currentPage = pointsExtract.extractData?.pagination?.page ?? 1;
   138вҶ’    const totalPages = pointsExtract.extractData?.pagination?.totalPages ?? 1;
   139вҶ’    const canLoadMore = currentPage < totalPages && !pointsExtract.isLoadingMore;
   140вҶ’
   141вҶ’    if (canLoadMore) {
   142вҶ’      getPointsExtract({ page: currentPage + 1 });
   143вҶ’    }
   144вҶ’  }, [
   145вҶ’    pointsExtract.extractData?.pagination,
   146вҶ’    pointsExtract.isLoadingMore,
   147вҶ’  ]);
   148вҶ’
   149вҶ’  const setTransactionsFilters = useCallback(
   150вҶ’    (filters: AppliedFilters) => {
   151вҶ’      pointsExtractActions.setTransactionsFilters(filters);
   152вҶ’    },
   153вҶ’    [pointsExtractActions],
   154вҶ’  );
   155вҶ’
   156вҶ’  const clearTransactionsFilters = useCallback(() => {
   157вҶ’    pointsExtractActions.clearTransactionsFilters();
   158вҶ’  }, [pointsExtractActions]);
   159вҶ’
   160вҶ’  const getTransactionsWithFilters = useCallback(
   161вҶ’    (transactions: PointsTransaction[]): PointsTransaction[] => {
   162вҶ’      let filtered = transactions;
   163вҶ’
   164вҶ’      if (appliedTransactionsFilters) {
   165вҶ’        const filtersWithDays: AppliedFilters = {
   166вҶ’          ...appliedTransactionsFilters,
   167вҶ’          period: appliedTransactionsFilters.period !== undefined
   168вҶ’            ? PERIOD_DAYS_MAP[appliedTransactionsFilters.period]
   169вҶ’            : undefined,
   170вҶ’        };
   171вҶ’        filtered = getFilteredTransactions(filtered, filtersWithDays);
   172вҶ’      }
   173вҶ’
   174вҶ’      return filtered;
   175вҶ’    },
   176вҶ’    [appliedTransactionsFilters],
   177вҶ’  );
   178вҶ’
   179вҶ’  const getExtractData = useMemo(() => {
   180вҶ’    if (!pointsExtract.extractData) return undefined;
   181вҶ’
   182вҶ’    const transactions = getTransactionsWithFilters(
   183вҶ’      pointsExtract.extractData.transactions,
   184вҶ’    );
   185вҶ’
   186вҶ’    return {
   187вҶ’      ...pointsExtract.extractData,
